    <Subcommand extends readonly [Command<any, any, any, any>, ...Array<Command<any, any, any, any>>]>(subcommands: Subcommand): <Name extends string, R, E, A>(self: Command<Name, R, E, A>) => Command<Name, R | Exclude<Effect.Context<ReturnType<Subcommand[number]["handler"]>>, Command.Context<Name>>, E | Effect.Error<ReturnType<Subcommand[number]["handler"]>>, Descriptor.Command.ComputeParsedType<A & Readonly<{
